import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx';
import './KhaiBaoCoSo.css';
import speciesOptions from '../data/speciesData';
import { jwtDecode } from 'jwt-decode';
import { useNavigate } from 'react-router-dom';

function KhaiBaoCoSo() {
  const navigate = useNavigate();
  const initialFormState = { /* ... giữ nguyên state của bạn ... */ };
  
  const [formData, setFormData] = useState(initialFormState);
  
  // === BƯỚC 1: THÊM STATE ĐỂ QUẢN LÝ VIỆC ĐÓNG/MỞ ===
  const [openSections, setOpenSections] = useState({
    thongTinCoSo: true,
    nguoiDaiDien: true,
    loaiCoSo: true,
    thongTinGayNuoi: false,
    thongTinKinhDoanhGo: false,
    giayPhep: false,
    upload: true,
  });
  
  // ... các state khác giữ nguyên ...

  // === BƯỚC 2: TẠO HÀM ĐỂ BẬT/TẮT SECTION ===
  const toggleSection = (sectionName) => {
    setOpenSections(prev => ({
      ...prev,
      [sectionName]: !prev[sectionName]
    }));
  };

  // ... các hàm useEffect, handleChange, handleSubmit, ... giữ nguyên ...

  return (
    <div className="khai-bao-container">
      <h2>Đăng ký cơ sở</h2>
      {/* ... thông báo ... */}
      <form onSubmit={handleSubmit} className="khai-bao-form">

        {/* === BƯỚC 3: CẬP NHẬT LẠI CẤU TRÚC JSX === */}
        <section className="khai-bao-section">
          <h3 onClick={() => toggleSection('thongTinCoSo')} className="section-title-clickable">
            Thông tin cơ sở
          </h3>
          {openSections.thongTinCoSo && (
            <>
              {/* Đặt tất cả các div.form-group của section này vào đây */}
              <div className="form-group">
                <label htmlFor="tenCoSo">Tên cơ sở:</label>
                <input type="text" id="tenCoSo" name="tenCoSo" value={formData.tenCoSo} onChange={handleChange} required />
              </div>
              {/* ... và các trường khác ... */}
            </>
          )}
        </section>

        <section className="khai-bao-section">
          <h3 onClick={() => toggleSection('nguoiDaiDien')} className="section-title-clickable">
            Thông tin người đại diện
          </h3>
          {openSections.nguoiDaiDien && (
            <>
              {/* Đặt tất cả các div.form-group của section này vào đây */}
              <div className="form-group">
                <label htmlFor="tenNguoiDaiDien">Tên người đại diện:</label>
                <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={formData.tenNguoiDaiDien} onChange={handleChange} required />
              </div>
              {/* ... và các trường khác ... */}
            </>
          )}
        </section>

        <section className="khai-bao-section">
          <h3 onClick={() => toggleSection('loaiCoSo')} className="section-title-clickable">
            Loại cơ sở đăng ký
          </h3>
          {openSections.loaiCoSo && (
            <div className="form-group">
              <label htmlFor="loaiCoSoDangKy">Chọn loại cơ sở đăng ký:</label>
              <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={formData.loaiCoSoDangKy} onChange={handleChange} required>
                <option value="">-- Chọn loại --</option>
                <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi (Động vật/Thực vật)</option>
                <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
              </select>
            </div>
          )}
        </section>
        
        {/* Áp dụng tương tự cho các section còn lại */}

        <div className="form-actions">
          {/* ... các nút bấm ... */}
        </div>
      </form>
      
      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          <h3 onClick={() => toggleSection('upload')} className="section-title-clickable">
            Tải lên hàng loạt từ file CSV
          </h3>
          {openSections.upload && (
            <>
              {/* ... phần upload file của bạn ... */}
            </>
          )}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
